ee:message.ee:set-payload:
%dw 2.0
output application/json

var supplierMaster = [
  {"id": "SUP-COL", "name": "Colombo Auto Components Ltd", "country": "LK"},
  {"id": "SUP-IND", "name": "Bharat Spares Export", "country": "IN"}
]
---
{
	"reportType": "Local Supplier Restock Orders",


	"orders": (payload map (part) -> {
		"partNumber": part.partId,
		"partName": part.name,
		"quantity": part.qtyNeeded,
		"lineTotal": part.unitPrice * part.qtyNeeded,

		"supplierDetails": (supplierMaster filter (sup) -> sup.id == part.supplierId)[0] 
	}) filter (item) -> item.supplierDetails.country == "LK"
}
